  1→import type { Block, ImportJob } from "@chat-exporter/shared";
  2→import { useCallback, useEffect, useMemo, useRef, useState } from "react";
  3→
  4→import { ErrorBoundary } from "@/components/error-boundary";
  5→import { AdjustmentModeGuide } from "@/components/format-workspace/adjustment-mode-guide";
  6→import { AdjustmentPopover } from "@/components/format-workspace/adjustment-popover";
  7→import { ArtifactView } from "@/components/format-workspace/artifact-view";
  8→import { CompletedToolbar } from "@/components/format-workspace/completed-toolbar";
  9→import { DeleteMessageDialog } from "@/components/format-workspace/delete-message-dialog";
 10→import {
 11→  formatMarkdownLinesLabel,
 12→  formatMessageBlockLabel,
 13→  getImportStageLabel,
 14→  miscLabels,
 15→} from "@/components/format-workspace/labels";
 16→import { LoadingStateBlock } from "@/components/format-workspace/loading-state-block";
 17→import { MarkdownView } from "@/components/format-workspace/markdown-view";
 18→import { ReaderView } from "@/components/format-workspace/reader-view";
 19→import { copyMessageToClipboard } from "@/components/format-workspace/message-clipboard";
 20→import {
 21→  applyMarkdownRules,
 22→  buildReaderEffectsMap,
 23→} from "@/components/format-workspace/rule-engine";
 24→import { SaveIndicator } from "@/components/format-workspace/save-indicator";
 25→import { StatusHeader } from "@/components/format-workspace/status-header";
 26→import {
 27→  type AdjustmentSelection,
 28→  adjustableViews,
 29→  type EditMode,
 30→  type ViewMode,
 31→} from "@/components/format-workspace/types";
 32→import { UndoToast } from "@/components/format-workspace/undo-toast";
 33→import { useAdjustmentPopover } from "@/components/format-workspace/use-adjustment-popover";
 34→import { useAdjustmentSession } from "@/components/format-workspace/use-adjustment-session";
 35→import { useAutoSnapshot } from "@/components/format-workspace/use-auto-snapshot";
 36→import { useDeletionToast } from "@/components/format-workspace/use-deletion-toast";
 37→import { useFormatRules } from "@/components/format-workspace/use-format-rules";
 38→import { useMessageDeletion } from "@/components/format-workspace/use-message-deletion";
 39→import { useMessageEdits } from "@/components/format-workspace/use-message-edits";
 40→import { useResolvedConversation } from "@/components/format-workspace/use-resolved-conversation";
 41→import { useSnapshots } from "@/components/format-workspace/use-snapshots";
 42→import { VersionsModal } from "@/components/format-workspace/versions-modal";
 43→
 44→type ActiveStage = {
 45→  detail: string;
 46→  label: string;
 47→} | null;
 48→
 49→type FormatWorkspaceProps = {
 50→  activeStage: ActiveStage;
 51→  elapsedTime: string;
 52→  job: ImportJob;
 53→  view: ViewMode;
 54→  onViewChange: (view: ViewMode) => void;
 55→};
 56→
 57→function _describeSelectionLabel(selection: AdjustmentSelection) {
 58→  if (selection.lineStart !== undefined && selection.lineEnd !== undefined) {
 59→    return formatMarkdownLinesLabel(selection.lineStart, selection.lineEnd);
 60→  }
 61→
 62→  return formatMessageBlockLabel(
 63→    selection.messageRole,
 64→    selection.messageIndex + 1,
 65→    selection.blockType,
 66→  );
 67→}
 68→
 69→function renderArtifact(view: Exclude<ViewMode, "reader">, job: ImportJob) {
 70→  if (!job.artifacts) {
 71→    return "Artefakt ist noch nicht verfügbar.";
 72→  }
 73→
 74→  switch (view) {
 75→    case "markdown":
 76→      return job.artifacts.markdown;
 77→    case "handover":
 78→      return job.artifacts.handover;
 79→    case "json":
 80→      return job.artifacts.json;
 81→  }
 82→}
 83→
 84→export function FormatWorkspace({
 85→  activeStage,
 86→  elapsedTime,
 87→  job,
 88→  view,
 89→  onViewChange,
 90→}: FormatWorkspaceProps) {
 91→  const isAdjustableView = adjustableViews.has(view);
 92→
 93→  const session = useAdjustmentSession(view, job.id);
 94→  const rules = useFormatRules(view, job.id);
 95→  const snapshots = useSnapshots(job.id);
 96→  const messageEdits = useMessageEdits(job.id, snapshots.activeSnapshot?.id);
 97→  const resolvedMessages = useResolvedConversation(
 98→    job.conversation,
 99→    messageEdits.editedMessagesMap,
100→  );
101→  const autoSnapshot = useAutoSnapshot({
102→    activeSnapshot: snapshots.activeSnapshot,
103→    create: snapshots.create,
104→    activate: snapshots.activate,
105→  });
106→  const deletion = useMessageDeletion(job.id);
107→  const deletionToast = useDeletionToast();
108→  const [editMode, setEditMode] = useState<EditMode>("view");
109→
110→  const hasEdits = resolvedMessages.some((m) => m.isEdited);
111→
112→  // beforeunload warning when unsaved edits exist
113→  useEffect(() => {
114→    if (!messageEdits.isSaving) return;
115→    const handler = (e: BeforeUnloadEvent) => {
116→      e.preventDefault();
117→    };
118→    window.addEventListener("beforeunload", handler);
119→    return () => window.removeEventListener("beforeunload", handler);
120→  }, [messageEdits.isSaving]);
121→
122→  const handleBlocksChange = useCallback(
123→    (messageId: string, blocks: Block[]) => {
124→      void autoSnapshot.ensureSnapshot().then((ready) => {
125→        if (ready) {
126→          messageEdits.saveEdit(messageId, blocks);
127→        }
128→      });
129→    },
130→    [autoSnapshot, messageEdits],
131→  );
132→  const [versionsModalOpen, setVersionsModalOpen] = useState(false);
133→  const [deleteDialog, setDeleteDialog] = useState<{
134→    messageId: string;
135→    isRound: boolean;
136→    preview: string;
137→  } | null>(null);
138→  const popover = useAdjustmentPopover();
139→
140→  const handleDeleteMessage = useCallback(
141→    (messageId: string) => {
142→      const msg = job.conversation?.messages.find((m) => m.id === messageId);
143→      const preview =
144→        msg?.blocks
145→          .map((b) => ("text" in b ? b.text : b.type))
146→          .join(" ")
147→          .slice(0, 200) ?? messageId;
148→      setDeleteDialog({ messageId, isRound: false, preview });
149→    },
150→    [job.conversation?.messages],
151→  );
152→
153→  const handleDeleteRound = useCallback(
154→    (messageId: string) => {
155→      const msg = job.conversation?.messages.find((m) => m.id === messageId);
156→      const preview =
157→        msg?.blocks
158→          .map((b) => ("text" in b ? b.text : b.type))
159→          .join(" ")
160→          .slice(0, 200) ?? messageId;
161→      setDeleteDialog({ messageId, isRound: true, preview });
162→    },
163→    [job.conversation?.messages],
164→  );
165→
166→  const handleConfirmDelete = useCallback(
167→    async (reason?: string) => {
168→      if (!deleteDialog) return;
169→      const { messageId, isRound } = deleteDialog;
170→      setDeleteDialog(null);
171→      if (isRound) {
172→        const result = await deletion.deleteRound(messageId, reason);
173→        deletionToast.showDeletedToast(messageId, true, result.length);
174→      } else {
175→        await deletion.deleteMessage(messageId, reason);
176→        deletionToast.showDeletedToast(messageId, false);
177→      }
178→    },
179→    [deleteDialog, deletion, deletionToast],
180→  );
181→
182→  const handleUndoDelete = useCallback(async () => {
183→    if (!deletionToast.toast) return;
184→    await deletion.restoreMessage(deletionToast.toast.messageId);
185→    deletionToast.dismissToast();
186→  }, [deletion, deletionToast]);
187→
188→  const mergedRef = useCallback(
189→    (node: HTMLElement | null) => {
190→      (
191→        session.sectionRef as React.MutableRefObject<HTMLElement | null>
192→      ).current = node;
193→      (
194→        popover.containerRef as React.MutableRefObject<HTMLElement | null>
195→      ).current = node;
196→    },
197→    [session.sectionRef, popover.containerRef],
198→  );
199→
200→  const artifact = view === "reader" ? "" : renderArtifact(view, job);
201→  // Design-Entscheidung: Downloads erfolgen aus `displayedMarkdown`, das
202→  // `applyMarkdownRules` inklusive format_profile-Rules enthält. Der Server-
203→  // Endpoint `imports.exportArtifact` liefert hingegen rohe Artefakte ohne Rules.
204→  const displayedMarkdown = useMemo(() => {
205→    if (view !== "markdown") return artifact;
206→    try {
207→      return applyMarkdownRules(artifact, rules.activeRules);
208→    } catch {
209→      return artifact;
210→    }
211→  }, [artifact, rules.activeRules, view]);
212→
213→  const resolvedConversation = useMemo(() => {
214→    if (!job.conversation) return undefined;
215→    return {
216→      ...job.conversation,
217→      messages: resolvedMessages.map((rm) => ({
218→        id: rm.id,
219→        role: rm.role,
220→        blocks: rm.blocks,
221→      })),
222→    };
223→  }, [job.conversation, resolvedMessages]);
224→
225→  const readerEffectsMap = useMemo(
226→    () =>
227→      view === "reader" && resolvedConversation
228→        ? buildReaderEffectsMap(rules.activeRules, resolvedConversation)
229→        : new Map(),
230→    [rules.activeRules, resolvedConversation, view],
231→  );
232→
233→  const handleCopyMessage = useCallback(
234→    (messageId: string) => {
235→      const msg = resolvedConversation?.messages.find(
236→        (m) => m.id === messageId,
237→      );
238→      if (!msg) return;
239→      void copyMessageToClipboard(msg, view, msg.blocks);
240→    },
241→    [resolvedConversation, view],
242→  );
243→
244→  const handleDownload = useMemo(() => {
245→    if (view === "markdown") {
246→      return () => {
247→        const blob = new Blob([displayedMarkdown], { type: "text/markdown" });
248→        const url = URL.createObjectURL(blob);
249→        const a = document.createElement("a");
250→        a.href = url;
251→        a.download = `export-${job.id}.md`;
252→        document.body.appendChild(a);
253→        a.click();
254→        document.body.removeChild(a);
255→        setTimeout(() => URL.revokeObjectURL(url), 100);
256→      };
257→    }
258→    if (view === "reader" && resolvedConversation) {
259→      return () => {
260→        const html = resolvedConversation.messages
261→          .map((m) =>
262→            m.blocks
263→              .map((b) => ("text" in b ? b.text : JSON.stringify(b)))
264→              .join("\n"),
265→          )
266→          .join("\n\n---\n\n");
267→        const blob = new Blob([html], { type: "text/plain" });
268→        const url = URL.createObjectURL(blob);
269→        const a = document.createElement("a");
270→        a.href = url;
271→        a.download = `export-${job.id}.txt`;
272→        document.body.appendChild(a);
273→        a.click();
274→        document.body.removeChild(a);
275→        setTimeout(() => URL.revokeObjectURL(url), 100);
276→      };
277→    }
278→    if ((view === "handover" || view === "json") && artifact) {
279→      return () => {
280→        const ext = view === "json" ? "json" : "md";
281→        const blob = new Blob([artifact], { type: "text/plain" });
282→        const url = URL.createObjectURL(blob);
283→        const a = document.createElement("a");
284→        a.href = url;
285→        a.download = `export-${job.id}.${ext}`;
286→        document.body.appendChild(a);
287→        a.click();
288→        document.body.removeChild(a);
289→        setTimeout(() => URL.revokeObjectURL(url), 100);
290→      };
291→    }
292→    return undefined;
293→  }, [view, displayedMarkdown, job.id, resolvedConversation, artifact]);
294→  const showPopover =
295→    session.adjustModeEnabled &&
296→    Boolean(session.activeSelection) &&
297→    Boolean(session.activeAnchor);
298→
299→  const popoverCallbacksRef = useRef({
300→    handleDiscardSession: session.handleDiscardSession,
301→    activeSessionDetail: session.activeSessionDetail,
302→    handleRejectLastChange: rules.handleRejectLastChange,
303→    setReplyVisible: session.setReplyVisible,
304→  });
305→  popoverCallbacksRef.current = {
306→    handleDiscardSession: session.handleDiscardSession,
307→    activeSessionDetail: session.activeSessionDetail,
308→    handleRejectLastChange: rules.handleRejectLastChange,
309→    setReplyVisible: session.setReplyVisible,
310→  };
311→
312→  const handlePopoverClose = useCallback(() => {
313→    popoverCallbacksRef.current.handleDiscardSession();
314→  }, []);
315→
316→  const handleRejectLastChange = useCallback(() => {
317→    const {
318→      activeSessionDetail,
319→      handleRejectLastChange: reject,
320→      setReplyVisible,
321→    } = popoverCallbacksRef.current;
322→    if (activeSessionDetail) {
323→      void reject(activeSessionDetail).then((success) => {
324→        if (success) setReplyVisible(false);
325→      });
326→    }
327→  }, []);
328→
329→  const sessionError =
330→    session.activeSessionError ?? rules.disableError ?? rules.promoteError;
331→
332→  const viewErrorFallback = (_error: Error, reset: () => void) => (
333→    <div className="flex flex-col items-center justify-center gap-4 p-8 text-center">
334→      <p className="text-red-700">{miscLabels.viewLoadError}</p>
335→      <button
336→        className="rounded-lg border border-border px-4 py-2 text-sm hover:bg-foreground/5"
337→        type="button"
338→        onClick={reset}
339→      >
340→        {miscLabels.retryButton}
341→      </button>
342→    </div>
343→  );
344→
345→  return (
346→    <section
347→      ref={mergedRef}
348→      className="relative space-y-4 rounded-[1.9rem] border border-border/80 bg-background/70 p-4 sm:p-5"
349→    >
350→      <StatusHeader
351→        activeStage={activeStage}
352→        elapsedTime={elapsedTime}
353→        job={job}
354→      />
355→
356→      {job.warnings.length > 0 ? (
357→        <div className="rounded-2xl border border-amber-300/40 bg-amber-100/60 px-4 py-3 text-sm text-amber-950">
358→          {job.warnings[0]}
359→        </div>
360→      ) : null}
361→
362→      {job.status === "failed" ? (
363→        <div className="rounded-2xl border border-red-300/40 bg-red-100/70 p-4 text-red-900">
364→          <p className="font-medium">{miscLabels.importFailed}</p>
365→          {job.errorStage && job.errorStage !== "done" && (
366→            <p className="text-sm mt-1">
367→              {miscLabels.errorInPhase(getImportStageLabel(job.errorStage))}
368→            </p>
369→          )}
370→          {job.error && <p className="text-sm mt-1">{job.error}</p>}
371→        </div>
372→      ) : job.status === "queued" || job.status === "running" ? (
373→        <LoadingStateBlock stageDetail={activeStage?.detail} />
374→      ) : (
375→        <div className="space-y-4">
376→          <CompletedToolbar
377→            adjustModeEnabled={session.adjustModeEnabled}
378→            editMode={editMode}
379→            isAdjustableView={isAdjustableView}
380→            rules={rules}
381→            view={view}
382→            onDownloadMarkdown={handleDownload}
383→            onEditModeChange={setEditMode}
384→            onToggleAdjustMode={session.toggleAdjustMode}
385→            onViewChange={onViewChange}
386→            deletionsCount={deletion.deletionsCount}
387→            showDeleted={deletion.showDeleted}
388→            snapshotCount={snapshots.snapshots.length}
389→            onVersionsClick={() => setVersionsModalOpen(true)}
390→            onToggleShowDeleted={() =>
391→              deletion.setShowDeleted(!deletion.showDeleted)
392→            }
393→          />
394→
395→          {sessionError && !session.adjustModeEnabled ? (
396→            <div className="rounded-2xl border border-red-300/40 bg-red-100/70 px-4 py-3 text-sm text-red-900">
397→              {sessionError}
398→            </div>
399→          ) : null}
400→
401→          {view === "reader" ? (
402→            <ErrorBoundary fallback={viewErrorFallback}>
403→              <div className="space-y-2">
404→                <div className="flex justify-end">
405→                  <SaveIndicator
406→                    isSaving={messageEdits.isSaving}
407→                    hasEdits={hasEdits}
408→                  />
409→                </div>
410→                <ReaderView
411→                  activeRules={rules.activeRules}
412→                  conversation={resolvedConversation}
413→                  adjustModeEnabled={session.adjustModeEnabled}
414→                  editMode={editMode === "edit"}
415→                  effectsMap={readerEffectsMap}
416→                  highlightedRuleId={rules.hoveredRuleId}
417→                  selectedBlock={
418→                    view === "reader" ? session.activeSelection : null
419→                  }
420→                  onSelectBlock={session.handleSelectionChange}
421→                  deletedMessageIds={deletion.deletedMessageIds}
422→                  showDeleted={deletion.showDeleted}
423→                  onBlocksChange={handleBlocksChange}
424→                  onCopyMessage={handleCopyMessage}
425→                  onDeleteMessage={handleDeleteMessage}
426→                  onDeleteRound={handleDeleteRound}
427→                  onRestoreMessage={deletion.restoreMessage}
428→                />
429→              </div>
430→            </ErrorBoundary>
431→          ) : view === "markdown" ? (
432→            <ErrorBoundary fallback={viewErrorFallback}>
433→              <MarkdownView
434→                activeRules={rules.activeRules}
435→                content={displayedMarkdown}
436→                adjustModeEnabled={session.adjustModeEnabled}
437→                highlightedRuleId={rules.hoveredRuleId}
438→                selectedRange={session.activeSelection}
439→                onSelectLines={session.handleSelectionChange}
440→              />
441→            </ErrorBoundary>
442→          ) : (
443→            <ErrorBoundary fallback={viewErrorFallback}>
444→              <ArtifactView content={artifact} />
445→            </ErrorBoundary>
446→          )}
447→
448→          {session.showGuide ? (
449→            <AdjustmentModeGuide
450→              view={view}
451→              onDismiss={() => session.setGuideDismissed(true)}
452→            />
453→          ) : null}
454→
455→          <ErrorBoundary
456→            fallback={
457→              <div className="rounded-2xl border border-red-300/40 bg-red-100/70 px-4 py-3 text-sm text-red-900">
458→                {miscLabels.adjustmentLoadError}
459→              </div>
460→            }
461→          >
462→            <AdjustmentPopover
463→              anchor={session.activeAnchor ?? null}
464→              containerRef={session.sectionRef}
465→              draftMessage={session.activeDraftMessage}
466→              error={session.activeSessionError}
467→              isLoading={session.activeSessionLoading || session.isDiscarding}
468→              isSubmitting={session.isSubmitting}
469→              open={
470→                showPopover &&
471→                Boolean(session.activeSelection) &&
472→                Boolean(session.activeAnchor)
473→              }
474→              sessionDetail={session.activeSessionDetail}
475→              showReply={session.replyVisible}
476→              view={view}
477→              onClose={handlePopoverClose}
478→              onDraftMessageChange={session.handleDraftMessageChange}
479→              onRejectLastChange={handleRejectLastChange}
480→              onSubmitMessage={session.handleSubmitMessage}
481→            />
482→          </ErrorBoundary>
483→        </div>
484→      )}
485→
486→      {deleteDialog && (
487→        <DeleteMessageDialog
488→          messagePreview={deleteDialog.preview}
489→          isRound={deleteDialog.isRound}
490→          onConfirm={(reason) => {
491→            void handleConfirmDelete(reason);
492→          }}
493→          onCancel={() => setDeleteDialog(null)}
494→        />
495→      )}
496→
497→      {deletionToast.toast && (
498→        <UndoToast
499→          message={deletionToast.toast.message}
500→          onUndo={() => {
501→            void handleUndoDelete();
502→          }}
503→          onDismiss={deletionToast.dismissToast}
504→        />
505→      )}
506→
507→      <VersionsModal
508→        open={versionsModalOpen}
509→        onOpenChange={setVersionsModalOpen}
510→        snapshots={snapshots.snapshots}
511→        activeSnapshotId={snapshots.activeSnapshot?.id ?? null}
512→        onActivate={(snapshotId) => {
513→          void snapshots.activate(snapshotId);
514→        }}
515→        onDeactivate={() => {
516→          void snapshots.deactivate();
517→        }}
518→        onCreate={(label) => {
519→          void snapshots.create(label);
520→        }}
521→        onRename={(snapshotId, label) => {
522→          void snapshots.rename(snapshotId, label);
523→        }}
524→        onDelete={(snapshotId) => {
525→          void snapshots.delete(snapshotId);
526→        }}
527→      />
528→    </section>
529→  );
530→}
