 1→import type {
 2→  AdjustmentTargetFormat,
 3→  AdjustmentSelection as SharedAdjustmentSelection,
 4→} from "@chat-exporter/shared";
 5→
 6→export type ViewMode = Extract<
 7→  AdjustmentTargetFormat,
 8→  "reader" | "markdown" | "handover" | "json"
 9→>;
10→
11→export type AdjustmentSelection = SharedAdjustmentSelection;
12→
13→/**
14→ * Viewport-relative anchor coordinates as returned by `getBoundingClientRect()`.
15→ * Produced by child views (`ReaderView`, `MarkdownView`) and converted to
16→ * `FloatingAdjustmentAnchor` (container-relative) in `FormatWorkspace`.
17→ */
18→export type ViewportAnchor = {
19→  bottom: number;
20→  height: number;
21→  left: number;
22→  top: number;
23→  width: number;
24→};
25→
26→/**
27→ * Anchor coordinates for the floating adjustment popover.
28→ * All positional values (`top`, `bottom`, `left`) are **container-relative**,
29→ * i.e. relative to the `<section>` element rendered by `FormatWorkspace`,
30→ * not to the viewport.
31→ */
32→export type FloatingAdjustmentAnchor = {
33→  bottom: number;
34→  height: number;
35→  left: number;
36→  top: number;
37→  width: number;
38→};
39→
40→export type EditMode = "view" | "edit" | "adjust";
41→
42→export const adjustableViews = new Set<ViewMode>(["reader", "markdown"]);
