  1→import { useMutation, useQueryClient } from "@tanstack/react-query";
  2→import {
  3→  type FormEvent,
  4→  useCallback,
  5→  useEffect,
  6→  useReducer,
  7→  useRef,
  8→} from "react";
  9→
 10→import {
 11→  type AdjustmentSelection,
 12→  adjustableViews,
 13→  type ViewMode,
 14→  type ViewportAnchor,
 15→} from "@/components/format-workspace/types";
 16→import { orpc } from "@/lib/orpc";
 17→
 18→import {
 19→  createInitialState,
 20→  sessionReducer,
 21→} from "./adjustment-session-reducer";
 22→
 23→function extractErrorMessage(error: unknown, fallback: string): string {
 24→  return error instanceof Error ? error.message : fallback;
 25→}
 26→
 27→export function useAdjustmentSession(view: ViewMode, jobId: string) {
 28→  const sectionRef = useRef<HTMLElement | null>(null);
 29→  const debounceRef = useRef<ReturnType<typeof setTimeout> | null>(null);
 30→  const [state, dispatch] = useReducer(
 31→    sessionReducer,
 32→    undefined,
 33→    createInitialState,
 34→  );
 35→  const queryClient = useQueryClient();
 36→
 37→  const createSession = useMutation(
 38→    orpc.adjustments.createSession.mutationOptions(),
 39→  );
 40→
 41→  const appendMessage = useMutation(
 42→    orpc.adjustments.appendMessage.mutationOptions({
 43→      onSuccess: (nextDetail) => {
 44→        dispatch({ type: "APPEND_MESSAGE_SUCCESS", view, detail: nextDetail });
 45→        if (nextDetail.session.status === "applied")
 46→          queryClient.invalidateQueries({ queryKey: orpc.rules.list.key() });
 47→      },
 48→      onError: (error) => {
 49→        dispatch({
 50→          type: "SET_SESSION_ERROR",
 51→          error: extractErrorMessage(
 52→            error,
 53→            "Anpassungsnachricht konnte nicht gespeichert werden.",
 54→          ),
 55→        });
 56→      },
 57→    }),
 58→  );
 59→
 60→  const discardSession = useMutation(
 61→    orpc.adjustments.discard.mutationOptions({
 62→      onSuccess: () => dispatch({ type: "CLEAR_ADJUSTMENT_STATE", view }),
 63→      onError: (error) => {
 64→        if (state.activeSessionDetail?.session.status === "applied") {
 65→          dispatch({ type: "CLEAR_ADJUSTMENT_STATE", view });
 66→        } else {
 67→          dispatch({
 68→            type: "SET_SESSION_ERROR",
 69→            error: extractErrorMessage(
 70→              error,
 71→              "Anpassungssession konnte nicht verworfen werden.",
 72→            ),
 73→          });
 74→        }
 75→      },
 76→    }),
 77→  );
 78→
 79→  // Derived values
 80→  const isAdjustableView = adjustableViews.has(view);
 81→  const isAdjustModeEnabled = state.adjustModeByView[view];
 82→  const activeSelection = state.selectionByView[view];
 83→
 84→  // Disable adjust mode when switching to a non-adjustable view
 85→  useEffect(() => {
 86→    if (!isAdjustableView && isAdjustModeEnabled)
 87→      dispatch({ type: "SET_ADJUST_MODE", view, enabled: false });
 88→  }, [isAdjustModeEnabled, isAdjustableView, view]);
 89→
 90→  // Debounced session creation on selection change
 91→  useEffect(() => {
 92→    const currentSelection = state.selectionByView[view];
 93→    const activeSelectionKey = state.sessionSelectionKeyByView[view];
 94→    if (!isAdjustModeEnabled || !isAdjustableView || !currentSelection) return;
 95→
 96→    const nextSelectionKey = JSON.stringify(currentSelection);
 97→    if (
 98→      activeSelectionKey === nextSelectionKey &&
 99→      state.activeSessionDetail?.session.importId === jobId
100→    )
101→      return;
102→
103→    if (debounceRef.current !== null) clearTimeout(debounceRef.current);
104→
105→    debounceRef.current = setTimeout(() => {
106→      dispatch({ type: "SET_SESSION_ERROR", error: null });
107→      createSession.mutate(
108→        { importId: jobId, selection: currentSelection, targetFormat: view },
109→        {
110→          onSuccess: (detail) => {
111→            dispatch({ type: "SET_ACTIVE_SESSION_DETAIL", detail });
112→            dispatch({
113→              type: "SET_SESSION_SELECTION_KEY",
114→              view,
115→              key: nextSelectionKey,
116→            });
117→          },
118→          onError: (error) => {
119→            dispatch({
120→              type: "SET_SESSION_ERROR",
121→              error: extractErrorMessage(
122→                error,
123→                "Anpassungssession konnte nicht erstellt werden.",
124→              ),
125→            });
126→          },
127→        },
128→      );
129→    }, 250);
130→
131→    return () => {
132→      if (debounceRef.current !== null) clearTimeout(debounceRef.current);
133→    };
134→  }, [
135→    state.selectionByView[view],
136→    state.sessionSelectionKeyByView[view],
137→    state.activeSessionDetail,
138→    createSession.mutate,
139→    isAdjustModeEnabled,
140→    isAdjustableView,
141→    jobId,
142→    view,
143→  ]);
144→
145→  const toggleAdjustMode = useCallback(() => {
146→    if (!isAdjustableView) return;
147→    const nextEnabled = !state.adjustModeByView[view];
148→    dispatch({ type: "SET_ADJUST_MODE", view, enabled: nextEnabled });
149→    dispatch({ type: "SET_GUIDE_DISMISSED", view, dismissed: false });
150→    if (!nextEnabled) dispatch({ type: "CLEAR_ADJUSTMENT_STATE", view });
151→  }, [isAdjustableView, state.adjustModeByView, view]);
152→
153→  const handleSelectionChange = useCallback(
154→    (selection: AdjustmentSelection, anchor: ViewportAnchor) => {
155→      const container = sectionRef.current;
156→      const r = container?.getBoundingClientRect();
157→      const scrollTop = container?.scrollTop ?? 0;
158→      const adjusted = r
159→        ? {
160→            top: anchor.top - r.top + scrollTop,
161→            bottom: anchor.bottom - r.top + scrollTop,
162→            left: anchor.left - r.left,
163→            width: anchor.width,
164→            height: anchor.height,
165→          }
166→        : anchor;
167→      dispatch({
168→        type: "SELECTION_CHANGED",
169→        view,
170→        selection,
171→        anchor: adjusted,
172→      });
173→    },
174→    [view],
175→  );
176→
177→  // Stable refs for values used in callbacks — prevents useCallback from
178→  // getting new references when mutation objects or state change.
179→  const latestRef = useRef({
180→    activeSessionDetail: state.activeSessionDetail,
181→    draftMessageByView: state.draftMessageByView,
182→    appendMutate: appendMessage.mutate,
183→    discardMutate: discardSession.mutate,
184→  });
185→  latestRef.current = {
186→    activeSessionDetail: state.activeSessionDetail,
187→    draftMessageByView: state.draftMessageByView,
188→    appendMutate: appendMessage.mutate,
189→    discardMutate: discardSession.mutate,
190→  };
191→
192→  const handleSubmitMessage = useCallback(
193→    (event: FormEvent<HTMLFormElement>) => {
194→      event.preventDefault();
195→      const { activeSessionDetail, draftMessageByView, appendMutate } =
196→        latestRef.current;
197→      if (!activeSessionDetail) return;
198→      const content = draftMessageByView[view].trim();
199→      if (!content) return;
200→      dispatch({ type: "SET_SESSION_ERROR", error: null });
201→      appendMutate({
202→        sessionId: activeSessionDetail.session.id,
203→        content,
204→      });
205→    },
206→    [view],
207→  );
208→
209→  const handleDiscardSession = useCallback(() => {
210→    const { activeSessionDetail, discardMutate } = latestRef.current;
211→    if (!activeSessionDetail) {
212→      dispatch({ type: "CLEAR_ADJUSTMENT_STATE", view });
213→      return;
214→    }
215→    dispatch({ type: "SET_SESSION_ERROR", error: null });
216→    discardMutate({ sessionId: activeSessionDetail.session.id });
217→  }, [view]);
218→
219→  const handleDraftMessageChange = useCallback(
220→    (value: string) => dispatch({ type: "SET_DRAFT_MESSAGE", view, value }),
221→    [view],
222→  );
223→
224→  const setReplyVisible = useCallback(
225→    (visible: boolean) =>
226→      dispatch({ type: "SET_REPLY_VISIBLE", view, visible }),
227→    [view],
228→  );
229→
230→  const setGuideDismissed = useCallback(
231→    (dismissed: boolean) =>
232→      dispatch({ type: "SET_GUIDE_DISMISSED", view, dismissed }),
233→    [view],
234→  );
235→
236→  const clearCurrentAdjustmentState = useCallback(
237→    (targetView: ViewMode) =>
238→      dispatch({ type: "CLEAR_ADJUSTMENT_STATE", view: targetView }),
239→    [],
240→  );
241→
242→  return {
243→    sectionRef,
244→    adjustModeEnabled: isAdjustModeEnabled,
245→    activeSessionDetail: state.activeSessionDetail,
246→    activeSelection,
247→    activeAnchor: state.anchorByView[view],
248→    activeDraftMessage: state.draftMessageByView[view],
249→    activeSessionError: state.sessionError,
250→    activeSessionLoading: createSession.isPending,
251→    isSubmitting: appendMessage.isPending,
252→    isDiscarding: discardSession.isPending,
253→    showGuide:
254→      isAdjustModeEnabled &&
255→      !activeSelection &&
256→      !state.guideDismissedByView[view],
257→    replyVisible: state.replyVisibleByView[view],
258→    guideDismissed: state.guideDismissedByView[view],
259→    toggleAdjustMode,
260→    handleSelectionChange,
261→    handleDraftMessageChange,
262→    handleSubmitMessage,
263→    handleDiscardSession,
264→    clearCurrentAdjustmentState,
265→    setReplyVisible,
266→    setGuideDismissed,
267→  };
268→}
