  1→import type { AdjustmentSessionDetail } from "@chat-exporter/shared";
  2→
  3→import type {
  4→  AdjustmentSelection,
  5→  FloatingAdjustmentAnchor,
  6→  ViewMode,
  7→} from "@/components/format-workspace/types";
  8→
  9→export type SessionState = {
 10→  draftMessageByView: Record<ViewMode, string>;
 11→  adjustModeByView: Record<ViewMode, boolean>;
 12→  guideDismissedByView: Record<ViewMode, boolean>;
 13→  selectionByView: Record<ViewMode, AdjustmentSelection | null>;
 14→  anchorByView: Record<ViewMode, FloatingAdjustmentAnchor | null>;
 15→  replyVisibleByView: Record<ViewMode, boolean>;
 16→  sessionSelectionKeyByView: Record<ViewMode, string | null>;
 17→  activeSessionDetail: AdjustmentSessionDetail | null;
 18→  sessionError: string | null;
 19→};
 20→
 21→const falsy = <T>(v: T): Record<ViewMode, T> => ({
 22→  reader: v,
 23→  markdown: v,
 24→  handover: v,
 25→  json: v,
 26→});
 27→
 28→export function createInitialState(): SessionState {
 29→  return {
 30→    draftMessageByView: falsy(""),
 31→    adjustModeByView: falsy(false),
 32→    guideDismissedByView: falsy(false),
 33→    selectionByView: falsy(null),
 34→    anchorByView: falsy(null),
 35→    replyVisibleByView: falsy(false),
 36→    sessionSelectionKeyByView: falsy(null),
 37→    activeSessionDetail: null,
 38→    sessionError: null,
 39→  };
 40→}
 41→
 42→export type SessionAction =
 43→  | { type: "SET_DRAFT_MESSAGE"; view: ViewMode; value: string }
 44→  | { type: "SET_ADJUST_MODE"; view: ViewMode; enabled: boolean }
 45→  | { type: "SET_GUIDE_DISMISSED"; view: ViewMode; dismissed: boolean }
 46→  | {
 47→      type: "SET_SELECTION";
 48→      view: ViewMode;
 49→      selection: AdjustmentSelection | null;
 50→    }
 51→  | {
 52→      type: "SET_ANCHOR";
 53→      view: ViewMode;
 54→      anchor: FloatingAdjustmentAnchor | null;
 55→    }
 56→  | { type: "SET_REPLY_VISIBLE"; view: ViewMode; visible: boolean }
 57→  | { type: "SET_SESSION_SELECTION_KEY"; view: ViewMode; key: string | null }
 58→  | {
 59→      type: "SET_ACTIVE_SESSION_DETAIL";
 60→      detail: AdjustmentSessionDetail | null;
 61→    }
 62→  | { type: "SET_SESSION_ERROR"; error: string | null }
 63→  | { type: "CLEAR_ADJUSTMENT_STATE"; view: ViewMode }
 64→  | {
 65→      type: "SELECTION_CHANGED";
 66→      view: ViewMode;
 67→      selection: AdjustmentSelection;
 68→      anchor: FloatingAdjustmentAnchor;
 69→    }
 70→  | {
 71→      type: "APPEND_MESSAGE_SUCCESS";
 72→      view: ViewMode;
 73→      detail: AdjustmentSessionDetail;
 74→    };
 75→
 76→function setView<K extends keyof SessionState>(
 77→  state: SessionState,
 78→  key: K,
 79→  view: ViewMode,
 80→  value: SessionState[K] extends Record<ViewMode, infer V> ? V : never,
 81→): SessionState {
 82→  return {
 83→    ...state,
 84→    [key]: { ...(state[key] as Record<ViewMode, unknown>), [view]: value },
 85→  };
 86→}
 87→
 88→export function sessionReducer(
 89→  state: SessionState,
 90→  action: SessionAction,
 91→): SessionState {
 92→  switch (action.type) {
 93→    case "SET_DRAFT_MESSAGE":
 94→      return setView(state, "draftMessageByView", action.view, action.value);
 95→    case "SET_ADJUST_MODE":
 96→      return setView(state, "adjustModeByView", action.view, action.enabled);
 97→    case "SET_GUIDE_DISMISSED":
 98→      return setView(
 99→        state,
100→        "guideDismissedByView",
101→        action.view,
102→        action.dismissed,
103→      );
104→    case "SET_SELECTION":
105→      return setView(state, "selectionByView", action.view, action.selection);
106→    case "SET_ANCHOR":
107→      return setView(state, "anchorByView", action.view, action.anchor);
108→    case "SET_REPLY_VISIBLE":
109→      return setView(state, "replyVisibleByView", action.view, action.visible);
110→    case "SET_SESSION_SELECTION_KEY":
111→      return setView(
112→        state,
113→        "sessionSelectionKeyByView",
114→        action.view,
115→        action.key,
116→      );
117→    case "SET_ACTIVE_SESSION_DETAIL":
118→      return { ...state, activeSessionDetail: action.detail };
119→    case "SET_SESSION_ERROR":
120→      return { ...state, sessionError: action.error };
121→    case "CLEAR_ADJUSTMENT_STATE": {
122→      const v = action.view;
123→      let s = setView(state, "draftMessageByView", v, "");
124→      s = setView(s, "selectionByView", v, null);
125→      s = setView(s, "anchorByView", v, null);
126→      s = setView(s, "sessionSelectionKeyByView", v, null);
127→      s = setView(s, "replyVisibleByView", v, false);
128→      return { ...s, activeSessionDetail: null, sessionError: null };
129→    }
130→    case "SELECTION_CHANGED": {
131→      const { view, selection, anchor } = action;
132→      let s = setView(state, "selectionByView", view, selection);
133→      s = setView(s, "anchorByView", view, anchor);
134→      s = setView(s, "guideDismissedByView", view, true);
135→      s = setView(s, "replyVisibleByView", view, false);
136→      return { ...s, sessionError: null };
137→    }
138→    case "APPEND_MESSAGE_SUCCESS": {
139→      const { view, detail } = action;
140→      let s = setView(state, "draftMessageByView", view, "");
141→      s = setView(s, "replyVisibleByView", view, true);
142→      return { ...s, activeSessionDetail: detail };
143→    }
144→  }
145→}
