17→/**
18→ * Read the DOM content of the editable element and construct a new Block
19→ * that matches the original block's type, preserving type-specific fields
20→ * (e.g. heading level, code language, list ordered flag).
21→ */
22→function readBlockFromDom(element: HTMLElement, original: Block): Block {
23→  switch (original.type) {
24→    case "paragraph":
25→      return { type: "paragraph", text: element.textContent ?? "" };
26→
27→    case "heading":
28→      return {
29→        type: "heading",
30→        level: original.level,
31→        text: element.textContent ?? "",
32→      };
33→
34→    case "quote":
35→      return { type: "quote", text: element.textContent ?? "" };
36→
37→    case "code":
38→      return {
39→        type: "code",
40→        language: original.language,
41→        text: element.textContent ?? "",
42→      };
43→
44→    case "list": {
45→      const listItems = element.querySelectorAll("li");
46→      const items = Array.from(listItems).map((li) => li.textContent ?? "");
47→      return {
48→        type: "list",
49→        ordered: original.ordered,
50→        items: items.length > 0 ? items : [element.textContent ?? ""],
51→      };
52→    }
53→
54→    case "table": {
55→      const thElements = element.querySelectorAll("th");
56→      const headers = Array.from(thElements).map((th) => th.textContent ?? "");
57→
58→      const bodyRows = element.querySelectorAll("tbody tr");
59→      const rows = Array.from(bodyRows).map((tr) => {
60→        const cells = tr.querySelectorAll("td");
61→        return Array.from(cells).map((td) => td.textContent ?? "");
62→      });
63→
64→      return { type: "table", headers, rows };
65→    }
66→
67→    default:
68→      return original;
69→  }
70→}
