458→                {miscLabels.adjustmentLoadError}
459→              </div>
460→            }
461→          >
462→            <AdjustmentPopover
463→              anchor={session.activeAnchor ?? null}
464→              containerRef={session.sectionRef}
465→              draftMessage={session.activeDraftMessage}
466→              error={session.activeSessionError}
467→              isLoading={session.activeSessionLoading || session.isDiscarding}
468→              isSubmitting={session.isSubmitting}
469→              open={
470→                showPopover &&
471→                Boolean(session.activeSelection) &&
472→                Boolean(session.activeAnchor)
473→              }
474→              sessionDetail={session.activeSessionDetail}
475→              showReply={session.replyVisible}
476→              view={view}
477→              onClose={handlePopoverClose}
478→              onDraftMessageChange={session.handleDraftMessageChange}
479→              onRejectLastChange={handleRejectLastChange}
480→              onSubmitMessage={session.handleSubmitMessage}
481→            />
482→          </ErrorBoundary>
483→        </div>
484→      )}
485→
486→      {deleteDialog && (
487→        <DeleteMessageDialog
